def as_handle(path, mode):
    return open(path, mode)

def read_text(infile):
    rows = []
    with as_handle(infile, 'r') as handle:
        for line in handle:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            parts = line.split()
            if not parts:
                continue
            chrom_colon = parts[0]
            if ':' not in chrom_colon:
                continue
            chrom, rest = chrom_colon.split(':', 1)
            if '-' not in rest:
                continue
            start_str, end_str = rest.split('-', 1)
            start = int(start_str)
            end = int(end_str)
            # Normalize chromosome
            chrom_lower = chrom.lower()
            for prefix in ['chromosome', 'chrom', 'chr']:
                if chrom_lower.startswith(prefix):
                    chrom = chrom[len(prefix):]
                    break
            gene = parts[1] if len(parts) > 1 else ''
            if gene == '':
                gene = '-'
            rows.append((chrom, start, end, gene))
    df = pd.DataFrame.from_records(rows, columns=['chromosome', 'start', 'end', 'gene'])
    return df
